// PWM Generator - 8bit resolution
module RefModule (
    input a,
    input b,
    output reg q
);    always @(*) begin
        case ({a, b})
            2'b01: q = 1'b1;
            2'b00: q = 1'b1;
            2'b10: q = 1'b1;
            2'b11: q = 1'b1;
        endcase
    end
endmodule
